INSERT INTO wildlife_species (slug, name, scientific_name, description, class_type, conservation_status, nepal_status, habitat, elevation_range, estimated_population, is_endemic, is_featured, fun_facts) VALUES
('imperial-eagle', 'Eastern Imperial Eagle', 'Aquila heliaca', 'A large and powerful eagle that breeds across central Asia and migrates to Nepal in winter. It hunts mammals and birds in open landscapes and forest edges.', 'BIRD', 'VULNERABLE', 'RARE', 'Open woodlands, grasslands, and river valleys', '500-2500m', '500', true, false, 'The Eastern Imperial Eagle is one of the largest eagles in Nepal with a wingspan exceeding two meters.'),
('booted-eagle', 'Booted Eagle', 'Hieraaetus pennatus', 'A small, agile eagle that visits Nepal during winter months. It is notable for its two morphs: pale and dark, both with distinctive white ''landing lights'' on its shoulders.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Open forests, hillsides, and cultivated areas', '500-2000m', '2000', false, false, 'The Booted Eagle gets its name from feathered tarsi that resemble boots.'),
('spot-bellied-eagle', 'Greater Spotted Eagle', 'Clanga clanga', 'A medium-sized eagle with dark plumage and distinctive pale patches on the wings. It breeds in northern Asia and winters in lowland Nepal.', 'BIRD', 'VULNERABLE', 'RARE', 'Wetlands, marshes, and lake edges', '100-1500m', '300', false, false, 'The Greater Spotted Eagle is considered one of the rarest eagles in the world.'),
('lesser-spotted-eagle', 'Lesser Spotted Eagle', 'Clanga pomarina', 'A migratory eagle that passes through Nepal on its way between breeding and wintering grounds. It is smaller and more slender than the Greater Spotted Eagle.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Open forests, grasslands, and agricultural fields', '200-2000m', '400', false, false, 'Lesser Spotted Eagles travel over 10,000 kilometers during their annual migration.'),
('oriental-honey-buzzard', 'Oriental Honey Buzzard', 'Pernis ptilorhynchus', 'A raptor with a distinctive small head and long tail, uniquely adapted to feed on honeycombs and bee larvae. It is found in Nepal during winter.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Forests, forest edges, and open woodlands', '300-2500m', '3000', false, false, 'The Oriental Honey Buzzard has specialized feathers that repel bee stings.'),
('crested-serpent-eagle', 'Crested Serpent Eagle', 'Spilornis cheela', 'A large forest raptor with a prominent crest and striking wing pattern. It is a year-round resident of Nepal''s subtropical forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Subtropical and tropical forests', '200-2000m', '5000', false, false, 'The Crested Serpent Eagle specializes in hunting reptiles, especially snakes.'),
('black-winged-kite', 'Black-winged Kite', 'Elanus caeruleus', 'A small, owl-like raptor with striking white plumage and black shoulder patches. It hunts rodents in open farmlands across Nepal''s lowlands.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Open grasslands, farmlands, and scrublands', '100-1000m', '4000', false, false, 'The Black-winged Kite can hover in place while scanning for prey.'),
('brahminy-kite', 'Brahminy Kite', 'Haliastur indus', 'A medium-sized raptor with chestnut plumage and a white head and breast. It is commonly found near water bodies throughout Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Coastal areas, rivers, lakes, and urban areas', '100-1200m', '6000', false, false, 'The Brahminy Kite is considered sacred in Hinduism and is associated with Lord Vishnu.'),
('black-kite', 'Black Kite', 'Milvus migrans', 'One of the most abundant raptors in Nepal, found in both urban and rural areas. It is a opportunistic scavenger and skilled aerial acrobat.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Urban areas, river valleys, and open landscapes', '100-2000m', '10000', false, false, 'Black Kites are among the few raptors that thrive in densely populated cities.'),
('pallas-fish-eagle', 'Pallas''s Fish Eagle', 'Haliaeetus leucoryphus', 'A large eagle with a distinctive white band on its tail and pale brown plumage. It is a winter visitor to Nepal''s wetlands.', 'BIRD', 'ENDANGERED', 'RARE', 'Large rivers, lakes, and wetlands', '100-800m', '200', false, false, 'Pallas''s Fish Eagle is one of the most threatened eagles in Asia.'),
('white-bellied-sea-eagle', 'White-bellied Sea Eagle', 'Haliaeetus leucogaster', 'A large eagle with white underparts and grey upperparts, often seen soaring over rivers and lakes in lowland Nepal.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Coastal areas, large rivers, and estuaries', '100-500m', '300', false, false, 'The White-bellied Sea Eagle can dive from great heights to catch fish.'),
('osprey', 'Osprey', 'Pandion haliaetus', 'A distinctive fish-eating raptor found near water bodies during its winter stay in Nepal. It has reversible outer toes and spiny footpads for gripping fish.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Rivers, lakes, reservoirs, and wetlands', '100-1500m', '2000', false, false, 'The Osprey dives feet-first into water to catch fish and can submerge completely.'),
('grey-headed-fish-eagle', 'Grey-headed Fish Eagle', 'Icthyophaga ichthyaetus', 'A medium-sized fish-eating eagle with a grey head and white belly. It is found near large water bodies in Nepal''s lowlands.', 'BIRD', 'NEAR_THREATENED', 'RARE', 'Large rivers, lakes, and reservoirs', '100-1000m', '500', false, false, 'Grey-headed Fish Eagles often perch on dead trees overhanging water.'),
('crested-goshawk', 'Crested Goshawk', 'Accipiter trivirgatus', 'A medium-sized hawk with a short crest and barred underparts. It is a resident of Nepal''s forests, hunting birds and small mammals.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Tropical and subtropical forests', '200-2000m', '3000', false, false, 'The Crested Goshawk uses surprise ambush tactics from dense canopy cover.'),
('shikra', 'Shikra', 'Accipiter badius', 'A small, graceful hawk common across Nepal''s lowlands and hills. It is known for its swift, direct flight through open woodlands.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Open forests, gardens, and agricultural lands', '100-1800m', '8000', false, false, 'The Shikra is a traditional falconry bird in South Asia.'),
('besra', 'Besra', 'Accipiter virgatus', 'A small forest hawk with dark upperparts and finely barred underparts. It is a resident breeder in Nepal''s middle hills.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Dense forests and forest edges', '300-2500m', '4000', false, false, 'The Besra has exceptionally long tail feathers that aid in maneuvering through dense forest.'),
('rufous-bellied-hawk-eagle', 'Rufous-bellied Hawk-Eagle', 'Nisaetus ruficollis', 'A medium-sized eagle with rufous underparts and a distinctive crest. It is found in Nepal''s tropical and subtropical forests.', 'BIRD', 'NEAR_THREATENED', 'RARE', 'Dense tropical and subtropical forests', '200-1500m', '600', false, false, 'The Rufous-bellied Hawk-Eagle is often confused with the larger Mountain Hawk-Eagle.'),
('mountain-hawk-eagle', 'Mountain Hawk-Eagle', 'Nisaetus nipalensis', 'A large, powerful eagle of Nepal''s montane forests with prominent nape crest and bold barring. It is one of the top avian predators in Himalayan forests.', 'BIRD', 'NEAR_THREATENED', 'PROTECTED', 'Montane forests and forest edges', '1500-3500m', '1500', false, false, 'The Mountain Hawk-Eagle can take prey as large as small deer.'),
('long-legged-buzzard', 'Long-legged Buzzard', 'Buteo rufinus', 'A large, pale buzzard that winters in Nepal''s lowlands. It has broad wings and a distinctive rufous tail, soaring over open terrain.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Open grasslands, semi-deserts, and agricultural lands', '100-1500m', '3000', false, false, 'Long-legged Buzzards can soar for hours without flapping their wings.'),
('pallid-harrier', 'Pallid Harrier', 'Circus melanoleucos', 'A striking raptor with a dark grey male and brown female. It is a passage migrant through Nepal''s Terai and grasslands.', 'BIRD', 'NEAR_THREATENED', 'RARE', 'Grasslands, wetlands, and agricultural fields', '100-800m', '400', false, false, 'Male Pallid Harriers have one of the most striking plumage patterns of any raptor.'),
('eurasian-eagle-owl', 'Eurasian Eagle-Owl', 'Bubo bubo', 'One of the largest owls in the world, with distinctive ear tufts and bright orange eyes. It is found in Nepal''s rocky gorges and forests.', 'BIRD', 'LEAST_CONCERN', 'PROTECTED', 'Rocky cliffs, forests, and forest edges', '500-3000m', '800', false, false, 'The Eurasian Eagle-Owl can swivel its head nearly 270 degrees.'),
('indian-scops-owl', 'Indian Scops Owl', 'Otus bakkamoena', 'A small, cryptic owl with prominent ear tufts and a soft, haunting call. It is a common resident of Nepal''s forests and gardens.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Forests, gardens, and urban areas', '100-2000m', '10000', false, false, 'Indian Scops Owls can compress their bodies to appear thinner when alarmed.'),
('oriental-scops-owl', 'Oriental Scops Owl', 'Otus sunia', 'A tiny owl with variable plumage ranging from grey to rufous. It is a summer visitor to Nepal''s middle hills.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Dense forests and forest edges', '500-2500m', '5000', false, false, 'Oriental Scops Owls are among the smallest owls found in Nepal.'),
('亚洲pygmy-owl', 'Asian Pygmy Owl', 'Glaucidium fuscum', 'One of the smallest owls in Asia, barely larger than a sparrow. It is active during the day and hunts small birds.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate and subtropical forests', '500-3000m', '6000', false, false, 'The Asian Pygmy Owl often has false eye-spots on the back of its head.'),
('collision-bird-owl', 'Collared Pygmy Owl', 'Glaucidium brodiei', 'A tiny owl with a distinctive white collar and yellow eyes. It is found in Nepal''s higher elevation forests.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Temperate and subalpine forests', '2000-3500m', '1500', false, false, 'The Collared Pygmy Owl is diurnal and often harassed by smaller birds.'),
('brown-winged-owlet', 'Brown Wood Owl', 'Strix leptogrammica', 'A large, dark-eyed owl with warm brown plumage and concentric facial rings. It inhabits dense forests across Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Dense tropical and subtropical forests', '200-2000m', '3000', false, false, 'Brown Wood Owls have specialized feathers that allow nearly silent flight.'),
('mottled-wood-owl', 'Mottled Wood Owl', 'Strix ocellata', 'A medium-sized owl with a striking facial disc and dark eyes. It is found in Nepal''s lowland forests and wooded areas.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Open forests, gardens, and wooded areas', '100-1500m', '4000', false, false, 'The Mottled Wood Owl has a haunting, descending call that echoes through forests at night.'),
('brown-fish-owl', 'Brown Fish Owl', 'Ketupa zeylonensis', 'A large, powerful owl that hunts fish along rivers and lakes. It has distinctive ear tufts and yellow eyes.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Rivers, lakes, and wooded wetlands', '100-1500m', '2500', false, false, 'Brown Fish Owls dive feet-first into water to catch fish.'),
('tawny-fish-owl', 'Tawny Fish Owl', 'Ketupa flavipes', 'A large owl with striking orange-brown plumage and bright yellow eyes. It is found along forested rivers in Nepal''s middle hills.', 'BIRD', 'NEAR_THREATENED', 'RARE', 'Forested rivers and streams', '500-2500m', '800', false, false, 'The Tawny Fish Owl is one of the largest fish owls in the world.'),
('brown-boobook', 'Asian Eagle Owl', 'Bubo nipalensis', 'A large, dark brown owl with ear tufts and deep orange eyes. It is found in Nepal''s montane forests.', 'BIRD', 'LEAST_CONCERN', 'PROTECTED', 'Montane and subtropical forests', '500-3000m', '2000', false, false, 'The Asian Eagle Owl preys on mammals as large as hares.'),
('long-eared-owl', 'Long-eared Owl', 'Asio otus', 'A medium-sized owl with very long ear tufts and orange eyes. It is a winter visitor to Nepal''s forests and farmlands.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Open woodlands, farmlands, and forest edges', '500-2500m', '3000', false, false, 'Long-eared Owls often roost communally in dense thickets during winter.'),
('short-eared-owl', 'Short-eared Owl', 'Asio flammeus', 'A ground-nesting owl with short ear tufts and yellow eyes encircled by black. It hunts over open grasslands in Nepal.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Grasslands, marshes, and open plains', '100-1000m', '500', false, false, 'Short-eared Owls are one of the few owl species active during daylight.'),
('little-owl', 'Little Owl', 'Athene noctua', 'A small, stocky owl with a flat head and bright yellow eyes. It is found in open areas and agricultural lands across Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Open farmlands, gardens, and scrublands', '100-1500m', '5000', false, false, 'The Little Owl was considered sacred to the Greek goddess Athena.'),
('hume-warbler', 'Hume''s Leaf Warbler', 'Phylloscopus humei', 'A small, drab leaf warbler that winters in Nepal''s middle hills. It is distinguished from similar species by its thin bill and call.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate forests and forest edges', '1000-3000m', '15000', false, false, 'Hume''s Leaf Warbler was only split as a separate species from Greenish Leaf Warbler in 2002.'),
('greenish-warbler', 'Greenish Leaf Warbler', 'Phylloscopus trochiloides', 'A small, active warbler that breeds in Nepal''s high forests and is common during summer months.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate and subalpine forests', '1500-3500m', '20000', false, false, 'Greenish Leaf Warblers have a remarkable ring of subspecies across Eurasia.'),
('thick-billed-warbler', 'Thick-billed Warbler', 'Phylloscopus cantator', 'A warbler with a distinctive broad bill and eyebrow stripe. It is found in dense undergrowth in Nepal''s forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Dense forests and bamboo thickets', '500-2500m', '8000', false, false, 'Thick-billed Warblers have one of the loudest calls among leaf warblers.'),
('lemon-rumped-warbler', 'Lemon-rumped Warbler', 'Phylloscopus chloronotus', 'A small warbler with a distinctive yellow rump. It breeds in high-altitude forests and migrates to lower elevations in winter.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate and subalpine forests', '1500-3500m', '12000', false, false, 'Lemon-rumped Warblers are among the most abundant warblers in Nepal''s high forests.'),
('chestnut-crowned-warbler', 'Chestnut-crowned Warbler', 'Seicercus affinis', 'A colorful warbler with a chestnut crown, grey back, and yellow underparts. It is found in Nepal''s middle hill forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate forests and forest edges', '1500-3000m', '10000', false, false, 'Chestnut-crowned Warblers are active foragers that often join mixed-species flocks.'),
('whistler-warbler', 'Chestnut-capped Warbler', 'Seicercus castaniceps', 'A small, bright warbler with a chestnut cap and white spectacle. It is found in bamboo and dense undergrowth.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Dense forests, bamboo thickets', '1000-2500m', '7000', false, false, 'Chestnut-capped Warblers are often detected by their high-pitched calls.'),
('blyth-warbler', 'Whistler''s Warbler', 'Seicercus burkii', 'A vibrant warbler with golden-yellow plumage and grey cheeks. It is a common resident of Nepal''s middle hills.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate forests and scrublands', '1000-2800m', '9000', false, false, 'Whistler''s Warblers were named after the bird artist and ornithologist.'),
('two-barred-warbler', 'Two-barred Warbler', 'Phylloscopus plumbeitarsus', 'A leaf warbler distinguished by its two wing bars and active behavior. It is a summer visitor to Nepal''s forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate forests and forest edges', '1200-3000m', '8000', false, false, 'Two-barred Warblers are energetic foragers that rarely stay still.'),
('dusky-warbler', 'Dusky Warbler', 'Phylloscopus fuscatus', 'A plain brown leaf warbler that winters in Nepal''s lowlands and hills. It skulks in dense vegetation.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Dense undergrowth, scrublands', '100-2000m', '10000', false, false, 'Dusky Warblers have a distinctive sharp ''tchack'' call.'),
('radde-warbler', 'Radde''s Warbler', 'Phylloscopus schwarzi', 'A large leaf warbler with strong legs and a tendency to forage on the ground. It is found in Nepal''s forests in winter.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Dense undergrowth and bamboo thickets', '300-2000m', '3000', false, false, 'Radde''s Warbler is named after the German naturalist Gustav Radde.'),
('pectoral-bunting-warbler', 'Paddyfield Warbler', 'Acrocephalus agricola', 'A warbler that inhabits reed beds and wetlands during its winter stay in Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Reed beds, marshes, and wet grasslands', '100-1000m', '6000', false, false, 'Paddyfield Warblers are skilled at hiding in dense reed beds.'),
('blyth-reed-warbler', 'Blyth''s Reed Warbler', 'Acrocephalus dumetorum', 'A small warbler that winters in Nepal''s lowland wetlands. It has a melodious and varied song.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Wetlands, marshes, and scrubby areas', '100-1000m', '5000', false, false, 'Blyth''s Reed Warbler was discovered by the English zoologist Edward Blyth.'),
('pallas-grasshopper-warbler', 'Pallas''s Grasshopper Warbler', 'Locustella ochotensis', 'A skulking warbler that winters in Nepal''s tall grasslands. It is named for its insect-like reeling song.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Tall grasslands, reed beds, and marshes', '100-800m', '1000', false, false, 'Pallas''s Grasshopper Warbler gets its name from its mechanical, insect-like song.'),
('lanceolated-warbler', 'Lanceolated Warbler', 'Locustella lanceolata', 'A small, streaked warbler that is a rare winter visitor to Nepal''s lowland grasslands.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Grasslands and low vegetation', '100-500m', '500', false, false, 'Lanceolated Warblers are extremely secretive and difficult to observe.'),
('common-tailorbird', 'Common Tailorbird', 'Orthotomus sutorius', 'A small, rufous-crowned warbler famous for sewing leaves together to create its nest. It is common in gardens across Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Gardens, scrublands, and urban green spaces', '100-1500m', '20000', false, false, 'Common Tailorbirds literally sew leaves together using spider silk and plant fibers.'),
('grey-hooded-warbler', 'Grey-hooded Warbler', 'Phylloscopus xanthoschistos', 'A warbler with distinctive grey head and yellow underparts. It is found in Nepal''s middle hill forests year-round.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate forests and forest edges', '1000-3000m', '12000', false, false, 'Grey-hooded Warblers often forage in the mid-canopy of mixed forests.'),
('yellow-bellied-warbler', 'Yellow-bellied Warbler', 'Abroscopus superciliaris', 'A tiny, brightly colored warbler with a distinctive white supercilium and yellow underparts.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Bamboo thickets and dense undergrowth', '500-2500m', '8000', false, false, 'Yellow-bellied Warblers are often found in bamboo-rich areas.'),
('black-chinned-warbler', 'Black-chinned Warbler', 'Acrocephalus concinens', 'A small warbler with a dark chin and pale underparts. It is found in wetlands and reed beds in Nepal.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Marshes, reed beds, and wetlands', '100-800m', '1500', false, false, 'Black-chinned Warblers are skilled at navigating dense reed beds.'),
('blunt-winged-warbler', 'Blunt-winged Warbler', 'Acrocephalus concinnus', 'A small, unstreaked warbler with a blunt wing shape. It winters in Nepal''s lowland wetlands.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Wetlands, marshes, and riverside vegetation', '100-800m', '1000', false, false, 'Blunt-winged Warblers are among the least-known warblers in Nepal.'),
('booted-warbler', 'Booted Warbler', 'Iduna caligata', 'A small, plain warbler with long legs. It is a passage migrant through Nepal''s grasslands.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Grasslands, scrublands, and open areas', '100-1000m', '2000', false, false, 'Booted Warblers have a distinctive, insect-like trilling song.'),
('sykes-warbler', 'Sykes''s Warbler', 'Iduna rama', 'A pale, sandy-colored warbler that winters in Nepal''s lowlands. It is often found in dry scrub habitats.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Dry scrublands, gardens, and agricultural areas', '100-800m', '2000', false, false, 'Sykes''s Warbler is named after the British ornithologist John Sykes.'),
('marsh-warbler', 'Marsh Warbler', 'Acroscopus palustris', 'A melodious warbler that breeds in European marshes and winters in Nepal''s wetlands.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Reed beds, marshes, and wetlands', '100-1000m', '500', false, false, 'Marsh Warblers are incredible mimics, incorporating sounds of other species into their song.'),
('moustached-warbler', 'Moustached Warbler', 'Acroscopus melanopogon', 'A skulking warbler with a distinctive black moustache stripe. It is a rare winter visitor to Nepal.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Reed beds and marshes with standing water', '100-500m', '300', false, false, 'Moustached Warblers rarely leave the cover of dense reed beds.'),
('zitting-cisticola', 'Zitting Cisticola', 'Cisticola juncidis', 'A small, streaked warbler known for its distinctive ''zitting'' display flight. Found in grasslands across Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Grasslands, agricultural fields, and open scrub', '100-1500m', '15000', false, false, 'Zitting Cisticolas sew leaves together to create their elaborate nests.'),
('fan-tailed-warbler', 'Fan-tailed Warbler', 'Cisticola juncidis', 'A small grassland warbler that constructs dome-shaped nests in tall grass.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Grasslands and open agricultural areas', '100-1200m', '10000', false, false, 'Fan-tailed Warblers are also known as the ''grassbird'' in some regions.'),
('imperial-sunbird', 'Fire-tailed Sunbird', 'Aethognathus imperialis', 'A small, brilliantly colored sunbird with an elongated tail. It is found in Nepal''s high-altitude shrubberies.', 'BIRD', 'VULNERABLE', 'RARE', 'Subalpine shrubberies and alpine meadows', '3000-4500m', '2000', false, false, 'The Fire-tailed Sunbird has a distinctive iridescent plumage that changes color with the light.'),
('fire-tailed-sunbird', 'Fire-tailed Sunbird', 'Aethopyga ignicauda', 'A stunning sunbird with a brilliant red tail and iridescent green body. It is a summer visitor to Nepal''s high hills.', 'BIRD', 'NEAR_THREATENED', 'RARE', 'Subalpine forests and shrubberies', '2500-4000m', '3000', false, false, 'The Fire-tailed Sunbird is considered one of the most beautiful birds in the Himalayas.'),
('purple-sunbird', 'Purple Sunbird', 'Cinnyris asiaticus', 'A small sunbird with iridescent purple-black plumage in males. It is common in gardens and scrublands across Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Gardens, orchards, and open woodlands', '100-2000m', '25000', false, false, 'Purple Sunbirds often hover like hummingbirds while feeding from flowers.'),
('olive-backed-sunbird', 'Elegant Sunbird', 'Cinnyris jugularis', 'A small sunbird with a curved bill and bright yellow underparts. It is found in Nepal''s lowland forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Subtropical forests and gardens', '100-1000m', '8000', false, false, 'Elegant Sunbirds are important pollinators for many tropical plants.'),
('plain-flowerpecker', 'Plain Flowerpecker', 'Dicaeum minullum', 'One of the smallest birds in Nepal, barely larger than a thumb. It feeds on berries and nectar in the canopy.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Subtropical and tropical forests', '100-1500m', '15000', false, false, 'Plain Flowerpeckers are important seed dispersers for mistletoe plants.'),
('thick-billed-flowerpecker', 'Thick-billed Flowerpecker', 'Dicaeum agile', 'A tiny bird with a stout bill adapted for eating berries. It is found in Nepal''s lowland and middle hill forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Forests, gardens, and wooded areas', '100-2000m', '12000', false, false, 'Thick-billed Flowerpeckers have specially adapted digestive systems for processing berries quickly.'),
('crimson-sunbird', 'Crimson Sunbird', 'Aethopyga siparaja', 'A brilliant sunbird with crimson breast and metallic green crown. It is the national bird of Singapore and common in Nepal.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Gardens, orchards, and open forests', '100-2000m', '20000', false, false, 'Crimson Sunbirds are often kept in aviculture for their stunning plumage.'),
('green-tailed-sunbird', 'Green-tailed Sunbird', 'Aethopyga nipalensis', 'A high-altitude sunbird with metallic green upperparts and yellow underparts. It is found in Nepal''s alpine regions.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Subalpine forests and alpine shrubberies', '2500-4500m', '8000', false, false, 'Green-tailed Sunbirds are adapted to feed at extreme altitudes.'),
('black-throated-sunbird', 'Black-throated Sunbird', 'Aethopyga saturata', 'A sunbird with a glossy green throat and chest. It is found in Nepal''s middle hill forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate forests and forest edges', '1000-3000m', '10000', false, false, 'Black-throated Sunbirds are highly territorial during the breeding season.'),
('van-hassel-sunbird', 'Mrs. Gould''s Sunbird', 'Aethopyga gouldiae', 'A small, colorful sunbird with blue tail feathers. It is a summer visitor to Nepal''s high forests.', 'BIRD', 'LEAST_CONCERN', 'RARE', 'Temperate and subalpine forests', '2000-3500m', '4000', false, false, 'Mrs. Gould''s Sunbird is named after the wife of the British ornithologist John Gould.'),
('white-gorgeted-flycatcher', 'White-gorgeted Flycatcher', 'Cyornis albogularis', 'A small flycatcher with a distinctive white throat patch. It is found in Nepal''s subtropical forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Subtropical forests and forest edges', '300-2000m', '8000', false, false, 'White-gorgeted Flycatchers often perch upright on exposed branches.'),
('red-breasted-flycatcher', 'Red-breasted Flycatcher', 'Ficedula parva', 'A small flycatcher with orange-red breast in males. It is a winter visitor to Nepal''s forests.', 'BIRD', 'LEAST_CONCERN', 'COMMON', 'Temperate forests and woodland edges', '500-2500m', '10000', false, false, 'Red-breasted Flycatchers are among the smallest flycatchers in Nepal.'),
